nt-weight:800;display:flex;align-items:center;justify-content:space-between}.cleanup-summary::-webkit-details-marker{display:none}.cleanup-summary:after{content:'⌄';font-size:24px;color:var(--muted);transition:.2s}.card[open] .cleanup-summary:after{transform:rotate(180deg)}.cleanup-body{padding:0 24px 24px;border-top:1px solid var(--line)}.form-row{display:grid;grid-template-columns:minmax(220px,1.2fr) minmax(220px,1fr) auto;gap:16px;align-items:center;margin-top:24px}.welcome-grid{display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-top:22px}.field,.select,.textarea{width:100%;border:1px solid #d7dee8;border-radius:11px;padding:0 16px;background:#fff;color:var(--text);font-size:16px}.field,.select{height:54px}.textarea{min-height:150px;padding:14px 16px;resize:vertical;font:inherit}.periods{display:flex;border:1px solid #d7dee8;border-radius:11px;overflow:hidden;height:54px}.periods label{position:relative;display:flex;align-items:center;justify-content:center;min-width:92px;padding:0 18px;border-right:1px solid #d7dee8;cursor:pointer;font-weight:700}.periods label:last-child{border-right:0}.periods input{position:absolute;opacity:0}.periods label:has(input:checked){background:#eaf2ff;color:#155ac5}.switch-row{display:flex;align-items:center;justify-content:space-between;gap:18px;margin-top:20px;padding:16px 0;border-bottom:1px solid var(--line)}.switch-copy strong{display:block}.switch-copy span{display:block;margin-top:5px;color:var(--muted);font-size:14px}.switch{position:relative;width:52px;height:30px;flex:0 0 auto}.switch input{opacity:0;width:0;height:0}.slider{position:absolute;inset:0;border-radius:30px;background:#cfd7e2;cursor:pointer}.slider:before{content:"";position:absolute;width:24px;height:24px;left:3px;top:3px;border-radius:50%;background:#fff;transition:.2s}.switch input:checked+.slider{background:var(--blue)}.switch input:checked+.slider:before{transform:translateX(22px)}.actions{margin-top:20px}.delete-btn,.save-btn{border:0;border-radius:10px;background:var(--blue);color:#fff;font-weight:800;font-size:16px;padding:14px 24px;cursor:pointer}.delete-btn:disabled{opacity:.55;cursor:wait}.hint{margin-top:12px;color:var(--muted);font-size:14px;line-height:1.5}.flash,.errors{margin-bottom:16px;padding:14px 16px;border-radius:11px;font-weight:700}.flash{background:#eaf8f1;color:#13764b}.errors{background:#fff0f0;color:#a72d2d}.toast{position:fixed;right:24px;bottom:24px;max-width:420px;padding:16px 18px;border-radius:12px;color:#fff;font-weight:700;box-shadow:0 14px 40px rgba(0,0,0,.2);opacity:0;transform:translateY(20px);pointer-events:none;transition:.2s;z-index:100}.toast.show{opacity:1;transform:translateY(0)}.toast.success{background:#15803d}.toast.error{background:#b91c1c}.overlay{display:none}@media(max-width:900px){.form-row,.welcome-grid{grid-template-columns:1fr}.periods{width:100%}.periods label{flex:1;min-width:0}}@media(max-width:800px){.app{display:block}.sidebar{position:fixed;left:0;top:0;width:292px;transform:translateX(-105%);transition:.22s;z-index:30}body.menu-open .sidebar{transform:translateX(0)}.overlay{display:block;position:fixed;inset:0;background:rgba(2,10,23,.52);opacity:0;pointer-events:none;z-index:20}body.menu-open .overlay{opacity:1;pointer-events:auto}.main{padding:20px 16px}.menu-btn{display:grid;place-items:center}.heading h1{font-size:29px}.cleanup-summary{padding:18px}.cleanup-body{padding:0 18px 18px}.toast{left:16px;right:16px;bottom:16px}}
