<script>
const form=document.getElementById('cleanupForm');const toast=document.getElementById('toast');const button=form.querySelector('.delete-btn');
function showToast(message,type){toast.textContent=message;toast.className='toast '+type+' show';setTimeout(()=>toast.classList.remove('show'),5000)}
form.addEventListener('submit',async event=>{event.preventDefault();const data=new FormData(form);const period=data.get('period');const label=period==='all'?'все сообщения':period==='1'?'сообщения за 1 день':'сообщения за 10 дней';if(!confirm('Удалить '+label+'? Восстановить их будет невозможно.'))return;button.disabled=true;button.textContent='Удаление…';try{const response=await fetch('{{ route('users.messages.delete') }}',{method:'POST',headers:{'Accept':'application/json','X-CSRF-TOKEN':'{{ csrf_token() }}'},body:data});const result=await response.json();if(!response.ok||!result.ok){throw new Error(result.message||Object.values(result.errors||{}).flat()[0]||'Не удалось удалить сообщения.')}showToast(result.message||('Удалено сообщений: '+result.deleted),'success');form.closest('details').removeAttribute('open')}catch(error){showToast(error.message||'Произошла ошибка удаления.','error')}finally{button.disabled=false;button.textContent='Удалить'}});
</script>
